1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Customer = { yearsWithMHPCO: number };
3	type QuoteInput = {
4	  customer: Customer;
5	  items: Item[];
6	  previousContracts: number;
7	};
8	
9	const PROCESSING_FEE = 5;
10	const NEWCOMER_PER_ITEM_SURCHARGE_RATE = 0.1;
11	
12	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	};
17	
18	const basePremiumForItem = (item: Item): number =>
19	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
20	
21	const isNewcomer = (customer: Customer): boolean =>
22	  customer.yearsWithMHPCO === 0;
23	
24	const premiumForItem = (item: Item, customer: Customer): number => {
25	  const base = basePremiumForItem(item);
26	  const surcharge = isNewcomer(customer) ? base * NEWCOMER_PER_ITEM_SURCHARGE_RATE : 0;
27	  return base + surcharge;
28	};
29	
30	export const quote = (input: QuoteInput): { premium: number } => {
31	  const itemsTotal = input.items.reduce(
32	    (sum, item) => sum + premiumForItem(item, input.customer),
33	    0,
34	  );
35	  return { premium: itemsTotal + PROCESSING_FEE };
36	};
37	
38	export const claim = (_input: unknown): unknown => {
39	  return undefined;
40	};
